using System;
using System.Runtime.InteropServices;
using System.Threading;
using System.Threading.Tasks;
using SkiaSharp;

Console.WriteLine($"OS: {RuntimeInformation.OSDescription}");
Console.WriteLine($"Arch: {RuntimeInformation.ProcessArchitecture}");

try {
    using var typeface = SKTypeface.FromFamilyName("Arial");
    using var font = new SKFont(typeface, 16f, 1f, 0f);
    Console.WriteLine($"SKFont created OK: Size={font.Size}");
} catch (Exception ex) { Console.WriteLine($"CRASH: {ex.GetType().Name}: {ex.Message}"); }

for (int i = 0; i < 1000; i++) {
    using var typeface = SKTypeface.FromFamilyName("Arial");
    using var font = new SKFont(typeface, 12f + (i % 20), 1f, 0f);
}

var tasks = new Task[4];
int crashCount = 0;
for (int t = 0; t < 4; t++) {
    tasks[t] = Task.Run(() => {
        for (int i = 0; i < 500; i++) {
            try {
                using var typeface = SKTypeface.FromFamilyName("Arial");
                using var font = new SKFont(typeface, 14f, 1f, 0f);
                using var surface = SKSurface.Create(new SKImageInfo(50, 50));
                surface.Canvas.DrawText("test", 0, 25, font, new SKPaint());
            } catch { Interlocked.Increment(ref crashCount); }
        }
    });
}
Task.WaitAll(tasks);
Console.WriteLine($"Concurrent test crashes: {crashCount}");
Console.WriteLine("SUCCESS: test completed");
